    r[CANDLE_CANDLE_HIST_2_ASK_HIGH] = cell_dff(r[CANDLE_CANDLE_HIST_2_ASK_HIGH], candle_ask_high, cell_and(cell_eqmask(hist_slot, 2ULL), candle_bar_boundary));
    r[CANDLE_CANDLE_HIST_2_ASK_LOW] = cell_dff(r[CANDLE_CANDLE_HIST_2_ASK_LOW], candle_ask_low, cell_and(cell_eqmask(hist_slot, 2ULL), candle_bar_boundary));
    r[CANDLE_CANDLE_HIST_2_ASK_CLOSE] = cell_dff(r[CANDLE_CANDLE_HIST_2_ASK_CLOSE], candle_ask_close, cell_and(cell_eqmask(hist_slot, 2ULL), candle_bar_boundary));
    r[CANDLE_CANDLE_HIST_2_VOLUME_BID] = cell_dff(r[CANDLE_CANDLE_HIST_2_VOLUME_BID], candle_volume_bid, cell_and(cell_eqmask(hist_slot, 2ULL), candle_bar_boundary));
    r[CANDLE_CANDLE_HIST_2_VOLUME_ASK] = cell_dff(r[CANDLE_CANDLE_HIST_2_VOLUME_ASK], candle_volume_ask, cell_and(cell_eqmask(hist_slot, 2ULL), candle_bar_boundary));
    r[CANDLE_CANDLE_HIST_2_TRUE_RANGE_BID] = cell_dff(r[CANDLE_CANDLE_HIST_2_TRUE_RANGE_BID], candle_true_range_bid, cell_and(cell_eqmask(hist_slot, 2ULL), candle_bar_boundary));
    r[CANDLE_CANDLE_HIST_2_TRUE_RANGE_ASK] = cell_dff(r[CANDLE_CANDLE_HIST_2_TRUE_RANGE_ASK], candle_true_range_ask, cell_and(cell_eqmask(hist_slot, 2ULL), candle_bar_boundary));
    r[CANDLE_CANDLE_HIST_2_INTRABAR_QTY_DELTA] = cell_dff(r[CANDLE_CANDLE_HIST_2_INTRABAR_QTY_DELTA], candle_intrabar_qty_delta, cell_and(cell_eqmask(hist_slot, 2ULL), candle_bar_boundary));
    r[CANDLE_CANDLE_HIST_2_TAI] = cell_dff(r[CANDLE_CANDLE_HIST_2_TAI], tf_bar_start, cell_and(cell_eqmask(hist_slot, 2ULL), candle_bar_boundary));
    r[CANDLE_CANDLE_HIST_2_BAR_SEQ] = cell_dff(r[CANDLE_CANDLE_HIST_2_BAR_SEQ], candle_bar_seq, cell_and(cell_eqmask(hist_slot, 2ULL), candle_bar_boundary));
    r[CANDLE_CANDLE_HIST_3_BID_OPEN] = cell_dff(r[CANDLE_CANDLE_HIST_3_BID_OPEN], candle_bid_open, cell_and(cell_eqmask(hist_slot, 3ULL), candle_bar_boundary));
    r[CANDLE_CANDLE_HIST_3_BID_HIGH] = cell_dff(r[CANDLE_CANDLE_HIST_3_BID_HIGH], candle_bid_high, cell_and(cell_eqmask(hist_slot, 3ULL), candle_bar_boundary));
    r[CANDLE_CANDLE_HIST_3_BID_LOW] = cell_dff(r[CANDLE_CANDLE_HIST_3_BID_LOW], candle_bid_low, cell_and(cell_eqmask(hist_slot, 3ULL), candle_bar_boundary));
